// RAKITRAKATRA TWEEN - FIXED v1.0
(function(){
  var R = window.Rakitrakatra || {};
  if(typeof window.Rakitrakatra === 'undefined') window.Rakitrakatra = R;
  
  R.Tween = {
    _tweens: [],
    
    to: function(target, props, duration, easing, onComplete){
      var tween = {
        target: target,
        start: {},
        end: props,
        duration: duration || 1000,
        elapsed: 0,
        easing: easing || 'linear',
        onComplete: onComplete,
        active: true
      };
      for(var k in props){
        tween.start[k] = target[k] || 0;
      }
      this._tweens.push(tween);
      return tween;
    },
    
    animo: function(target, props, duration, onComplete){
      return this.to(target, props, duration, 'easeOut', onComplete);
    },
    
    update: function(dt){
      for(var i=this._tweens.length-1; i>=0; i--){
        var t = this._tweens[i];
        if(!t.active) continue;
        t.elapsed += dt * 1000;
        var p = Math.min(t.elapsed / t.duration, 1);
        var eased = p;
        if(t.easing === 'easeOut') eased = 1 - Math.pow(1-p, 3);
        if(t.easing === 'easeIn') eased = p*p*p;
        
        for(var k in t.end){
          t.target[k] = t.start[k] + (t.end[k] - t.start[k]) * eased;
        }
        if(p >= 1){
          t.active = false;
          if(t.onComplete) t.onComplete();
          this._tweens.splice(i,1);
        }
      }
    },
    
    stopAll: function(){
      this._tweens = [];
    }
  };
  
  // Auto update if Kianja exists
  if(R.Kianja){
    var originalHavaozy = R.Kianja.prototype.havaozy;
    R.Kianja.prototype.havaozy = function(dt){
      if(originalHavaozy) originalHavaozy.call(this, dt);
      R.Tween.update(dt);
    };
  }
  
  console.log('✅ rakitrakatra.tween.min.js FIXED');
})();
